/**
 * 为API请求生成带有认证令牌的请求头
 * @returns {Object} 包含Authorization字段的请求头对象
 */
export default function authHeader() {
  // 从localStorage获取用户信息
  const userStr = localStorage.getItem('user')
  let user = null
  
  if (userStr) {
    try {
      user = JSON.parse(userStr)
    } catch (e) {
      console.error('解析用户信息失败:', e)
      return {}
    }
  }
  
  // 如果存在用户和令牌，则添加到Authorization请求头
  if (user && user.token) {
    return { Authorization: 'Bearer ' + user.token }
  } else {
    return {}
  }
}
